// Normalise the document list from doc-server into the API shape
// the frontend expects.
const raw = $input.first().json;

// doc-server returns an array directly
const list = Array.isArray(raw) ? raw : [];

const docs = list.map(d => ({
  id:         d.id,
  filename:   d.filename,
  type:       (d.mime_type || '').includes('pdf')  ? 'pdf'
            : (d.mime_type || '').includes('word') ? 'docx'
            : (d.mime_type || '').includes('sheet') || (d.mime_type || '').includes('xlsx') ? 'xlsx'
            : 'document',
  chunks:     d.chunks  || 0,
  date:       d.uploaded_at || new Date().toISOString(),
  status:     d.status  || 'processing',
  fileSize:   d.file_size || 0,
  collection: d.collection || '',
  indexedAt:  d.indexed_at || null,
  error:      d.error_message || null,
}));

return [{ json: docs }];
